class UnifiedStep(RootModel[CanonicalStep | Any]):
    root: Annotated[
        CanonicalStep | Any,
        Field(
            description='A workflow step, preferring typed canonical variants and falling back to an\nopaque [`serde_json::Value`] for runner-specific types not yet part of the\nwire contract.\n\nSerialization is transparent: a [`CanonicalStep`] serializes with its flat\n`"type"`-tagged shape; [`UnifiedStep::Other`] serializes the wrapped value\nas-is. Deserialization tries the canonical shape first; any payload that\ndoes not match (unknown `"type"`, missing fields, or missing discriminator)\nis preserved as [`UnifiedStep::Other`].\n\nThis catch-all is what makes the type *robust* on the wire: a runner can\nemit a `{"type":"gate", ...}` step and a consumer using [`UnifiedStep`]\nwill round-trip it losslessly even though `gate` is not in the canonical\nset.\n\n## Layout note (`#[allow(large_enum_variant)]`)\n\n`Canonical` carries a [`CanonicalStep`] (~672 bytes) while `Other` carries\na [`serde_json::Value`] (~32 bytes). The size asymmetry is intentional and\nthe enum is not held in bulk by any hot path today — `UnifiedWorkflow.*_steps`\nremains `Vec<serde_json::Value>`. Boxing `Canonical` would save stack space\nin hypothetical dense `Vec<UnifiedStep>` consumers at the cost of an extra\nheap allocation per step everywhere else and noisier pattern-matching.'
        ),
    ]


class WorkflowStage(BaseModel):
    """
    A workflow stage — a self-contained unit of execution with its own
    setup / verification / agentic / completion steps and verification-agentic
    loop.

    Multi-stage workflows execute stages sequentially. Each stage gets its own
    verification-agentic loop, and later stages see full output from all prior
    stages. Step arrays are opaque `serde_json::Value` payloads pending the
    Wave 4 typed-step migration.
    """

    model_config = ConfigDict(
        extra='forbid',
    )
    agenticSteps: Annotated[
        list[UnifiedStep] | None,
        Field(description='Agentic phase steps for this stage.', validate_default=True),
    ] = []
    approvalGate: Annotated[
        bool | None,
        Field(
            description='Whether to pause for human approval after each agentic phase.'
        ),
    ] = False
    completionPromptsFirst: Annotated[
        bool | None,
        Field(
            description='When true, run completion prompt steps BEFORE automation steps.\nDefault (`false`) runs automation first, then prompts.'
        ),
    ] = False
    completionSteps: Annotated[
        list[UnifiedStep] | None,
        Field(
            description='Completion phase steps for this stage.', validate_default=True
        ),
    ] = []
    condition: Annotated[
        StageCondition | None,
        Field(
            description='Optional condition for stage execution. When set, the stage is\nevaluated against this condition before running. If the condition is\nnot met, the stage is skipped.'
        ),
    ] = None
    description: Annotated[
        str | None, Field(description='Description of what this stage does.')
    ] = ''
    id: Annotated[str | None, Field(description='Unique identifier (UUID v4).')] = ''
    inputs: Annotated[
        list[StageInput] | None, Field(description='Inputs required from prior stages.')
    ] = None
    maxIterations: Annotated[
        int | None,
        Field(
            description="Maximum iterations for this stage's verification-agentic loop.\n\n`None` (omitted in JSON) means no iteration cap — the loop terminates\non success, explicit stop, or fix-attempt exhaustion.",
            ge=0,
        ),
    ] = None
    model: Annotated[
        str | None, Field(description='Model override for this stage.')
    ] = None
    modelOverrides: Annotated[
        dict[str, ModelOverrideConfig] | None,
        Field(description='Per-phase model overrides for this stage.'),
    ] = None
    name: Annotated[str, Field(description='Display name for this stage.')]
    outputs: Annotated[
        list[StageOutput] | None,
        Field(
            description='Declared outputs that this stage produces for downstream stages.'
        ),
    ] = None
    provider: Annotated[
        str | None, Field(description='AI provider override for this stage.')
    ] = None
    retryPolicy: Annotated[
        RetryPolicy | None,
        Field(description='Retry policy for this stage (overrides per-step defaults).'),
    ] = None
    setupSteps: Annotated[
        list[UnifiedStep] | None,
        Field(
            description='Setup phase steps for this stage (polymorphic; see module docs).',
            validate_default=True,
        ),
    ] = []
    timeoutSeconds: Annotated[
        int | None,
        Field(
            description="Optional inactivity timeout in seconds for this stage's AI sessions.",
            ge=0,
        ),
    ] = None
    verificationSteps: Annotated[
        list[UnifiedStep] | None,
        Field(
            description='Verification phase steps for this stage.',
            validate_default=True,
        ),
    ] = []


